  function promiseAnyScbt(promises) {
    if (typeof Promise !== 'undefined' && typeof Promise.any === 'function') {
      return Promise.any(promises);
    }
    return new Promise(function (resolve, reject) {
      var n = promises.length;
      if (!n) {
        reject(new Error('empty'));
        return;
      }
      var left = n;
      var firstErr;
      promises.forEach(function (p) {
        Promise.resolve(p).then(resolve, function (e) {
          firstErr = firstErr || e;
          left -= 1;
          if (!left) reject(firstErr || new Error('all rejected'));
        });
      });
    });
  }

  function load() {
    openMenuIdx = null;
    if (!sourceIp) {
      render([], '', 'Missing source_ip (check context and fixed_variables in the widget URL).', false);
      return;
    }
    render([], '', null, true);
    var retriedWithoutStored = false;
    var lastHttp = '';

    function buildScbtCfxqlStrings() {
      var rc =
        resolvedPstreamCfxql != null && String(resolvedPstreamCfxql).trim()
          ? String(resolvedPstreamCfxql).trim()
          : '';
      var hasCustom = rc.length > 0;
      var esc = sourceIp.replace(/'/g, "''");
      return hasCustom
        ? [appendHistoryLeanProjection(rc, historyLeanProjection)]
        : [
            appendHistoryLeanProjection("source_ip is '" + esc + "' and status is 'Success'", historyLeanProjection),
            appendHistoryLeanProjection("source_ip = '" + esc + "' and status is 'Success'", historyLeanProjection),
          ];
    }

    function getScbtStems(skipStored) {
      if (!skipStored) {
        var stored = readStoredPstreamV2Prefix();
        if (stored !== null) return [pstreamDataStem(stored)];
      }
      var p = apiV2Prefix();
      var root = pstreamDataStem('');
      var app = pstreamDataStem(p);
      var stems = [root];
      if (p && app !== root) stems.push(app);
      return stems;
    }

    function applyStreamRowFilters(rows, requireConfigId, requireStatus) {
      var f = rows.filter(function (r) {
        return sameIp(r);
      });
      if (requireConfigId)
        f = f.filter(function (r) {
          return cid(r);
        });
      f = f.filter(function (r) {
        return matchesCustomerTag(r, customerTag);
      });
      if (requireStatus)
        f = f.filter(function (r) {
          return matchesStatus(r);
        });
      return f;
    }

    function finishFromRows(all, resUrl) {
      try {
        if (all.length > 0) {
          var pfx = pathPrefixBeforeApiV2(resUrl);
          if (pfx !== null) writeStoredPstreamV2Prefix(pfx);
        }
        var filtered = applyStreamRowFilters(all, true, true);
        stripHeavyStreamFields(filtered);
        filtered.sort(function (a, b) {
          return rowTime(b) - rowTime(a);
        });
        var stored = getStoredGoldenId();
        if (stored) {
          for (var si = 0; si < filtered.length; si++) {
            var rid = cid(filtered[si]);
            var isG = rid && rid === stored;
            filtered[si].golden_config = isG ? 'Yes' : 'No';
            filtered[si].goldenConfig = isG ? 'Yes' : 'No';
          }
        }
        var goldenId = stored || '';
        if (!goldenId) {
          for (var j = 0; j < filtered.length; j++) {
            if (normGolden(filtered[j]) === 'yes') {
              goldenId = cid(filtered[j]);
              break;
            }
          }
        }
        render(filtered, goldenId, null, false);
      } catch (procErr) {
        render([], '', String(procErr && procErr.message ? procErr.message : procErr), false);
      }
    }

    function tryLoad(skipStored) {
      var cfxqlStrings = buildScbtCfxqlStrings();
      var stems = getScbtStems(skipStored);
      var si = 0;
      var fetchHeaders = { 'Content-Type': 'application/json; charset=UTF-8' };

      function tryNextStem() {
        if (si >= stems.length) {
          if (!skipStored && !retriedWithoutStored && readStoredPstreamV2Prefix() !== null) {
            clearStoredPstreamV2Prefix();
            retriedWithoutStored = true;
            tryLoad(true);
            return;
          }
          var detail = lastHttp ? ' (' + lastHttp + ')' : '';
          render(
            [],
            '',
            'Could not load stream data.' + detail + ' (see browser Network tab for failing URLs)',
            false
