        }
        var stemPath = stems[si++];
        var urls = expandStemTryUrls(stemPath, cfxqlStrings);
        promiseAnyScbt(
          urls.map(function (u) {
            return fetch(u, { credentials: 'same-origin', headers: fetchHeaders })
              .then(function (r) {
